import React from 'react';

const UserRoleBadge = ({ role }) => {
  const roles = {
    citizen: { icon: '👤', label: 'Citoyen', color: '#0B3B5F' },
    political_party: { icon: '🏛️', label: 'Parti Politique', color: '#D4AF37' },
    civil_society: { icon: '🤝', label: 'Société Civile', color: '#CE1126' },
    admin: { icon: '⚙️', label: 'Administration', color: '#1A5A8A' }
  };

  const r = roles[role] || roles.citizen;

  return (
    <span className="role-badge" style={{ backgroundColor: r.color }}>
      <span>{r.icon}</span> {r.label}
    </span>
  );
};

export default UserRoleBadge;
